To proxy requests in an ASP.NET Core API, you can use the `HttpClient` class to send the request to the target endpoint and then return the response from the target endpoint. Here's an example of how you can do this:

```csharp
[ApiController]
[Route("api/[controller]")]
public class ProxyController : ControllerBase
{
    private readonly IHttpClientFactory _httpClientFactory;

    public ProxyController(IHttpClientFactory httpClientFactory)
    {
        _httpClientFactory = httpClientFactory;
    }

    [HttpGet("{id}")]
    public async Task<IActionResult> GetAsync([FromRoute] int id)
    {
        var client = _httpClientFactory.CreateClient();
        var request = new HttpRequestMessage(HttpMethod.Get, $"https://target-endpoint.com/api/{id}");
        request.Headers.Accept.Add(new MediaTypeWithQualityHeaderValue("application/json"));

        var response = await client.SendAsync(request);
        response.EnsureSuccessStatusCode();

        return new ObjectResult(await response.Content.ReadAsStringAsync())
        {
            StatusCode = (int)response.StatusCode
        };
    }
}
```

